# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import os
import sqlite3

class DocumentAccessControl:
    def __init__(self, db_path: str, root_dir: str | None = None):
        self.db_path = db_path
        self.root_dir = os.path.abspath(root_dir) if root_dir else None
        self._ensure_schema()

    def _ensure_schema(self) -> None:
        with sqlite3.connect(self.db_path) as conn:
            conn.execute(
                """CREATE TABLE IF NOT EXISTS permissions (
                       user_id   TEXT NOT NULL,
                       file_path TEXT NOT NULL,
                       can_read  INTEGER NOT NULL,
                       PRIMARY KEY (user_id, file_path)
                   )"""
            )
            conn.commit()

    def _normalized_path(self, file_path: str) -> str:
        abs_path = os.path.abspath(file_path)
        if self.root_dir and not abs_path.startswith(self.root_dir):
            raise PermissionError("Access outside permitted directory")
        return abs_path

    def _has_permission(self, user_id: str, file_path: str) -> bool:
        with sqlite3.connect(self.db_path) as conn:
            cur = conn.execute(
                "SELECT can_read FROM permissions WHERE user_id=? AND file_path=?",
                (user_id, file_path),
            )
            row = cur.fetchone()
            return bool(row and row[0])

    def read_file(self, user_id: str, file_path: str) -> bytes:
        file_path = self._normalized_path(file_path)
        if not self._has_permission(user_id, file_path):
            raise PermissionError(f"User {user_id!r} lacks read permission for {file_path!r}")
        with open(file_path, "rb") as f:
            return f.read()

